    private val handler = Handler(Looper.getMainLooper())

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        // Schedule a delayed update in 30 seconds
        handler.postDelayed({
            // This lambda captures 'this' (the Activity)
            textView.text = "Updated!"
        }, 30_000)
    }

    // BUG: Activity rotates at T+5s.
    // The delayed message sits in the queue for 25 more seconds,
    // holding a reference to the destroyed Activity.
}

questions.solution:
class MyActivity : AppCompatActivity() {
    private val handler = Handler(Looper.getMainLooper())

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handler.postDelayed({
            textView.text = "Updated!"
        }, 30_000)
    }

    override fun onDestroy() {
        super.onDestroy()
        // Remove ALL pending messages and callbacks
        handler.removeCallbacksAndMessages(null)
    }
}

